+    /// Classify a timing value into good/ok/bad color.
+    fn classify_timing_color(ms: f32, good: f32, ok: f32) -> PackedRgba {
+        if ms <= good {
+            PackedRgba::rgb(80, 200, 120) // green
+        } else if ms <= ok {
+            PackedRgba::rgb(220, 180, 50) // yellow
+        } else {
+            PackedRgba::rgb(220, 60, 60) // red
+        }
+    }
